145	function createAgentStream(): EventStream<AgentEvent, AgentMessage[]> {
146		return new EventStream<AgentEvent, AgentMessage[]>(
147			(event: AgentEvent) => event.type === "agent_end",
148			(event: AgentEvent) => (event.type === "agent_end" ? event.messages : []),
149		);
150	}
151	
152	/**
153	 * Main loop logic shared by agentLoop and agentLoopContinue.
154	 */
155	async function runLoop(
156		initialContext: AgentContext,
157		newMessages: AgentMessage[],
158		initialConfig: AgentLoopConfig,
159		signal: AbortSignal | undefined,
160		emit: AgentEventSink,
161		streamFn?: StreamFn,
162	): Promise<void> {
163		let currentContext = initialContext;
164		let config = initialConfig;
165		let firstTurn = true;
166		// Check for steering messages at start (user may have typed while waiting)
167		let pendingMessages: AgentMessage[] = (await config.getSteeringMessages?.()) || [];
168	
169		// Outer loop: continues when queued follow-up messages arrive after agent would stop
170		while (true) {
171			let hasMoreToolCalls = true;
172	
173			// Inner loop: process tool calls and steering messages
174			while (hasMoreToolCalls || pendingMessages.length > 0) {
175				if (!firstTurn) {
176					await emit({ type: "turn_start" });
177				} else {
178					firstTurn = false;
179				}
180	
181				// Process pending messages (inject before next assistant response)
182				if (pendingMessages.length > 0) {
183					for (const message of pendingMessages) {
184						await emit({ type: "message_start", message });
185						await emit({ type: "message_end", message });
186						currentContext.messages.push(message);
187						newMessages.push(message);
188					}
189					pendingMessages = [];
190				}
191	
192				// Stream assistant response
193				const message = await streamAssistantResponse(currentContext, config, signal, emit, streamFn);
194				newMessages.push(message);
195	
196				if (message.stopReason === "error" || message.stopReason === "aborted") {
197					await emit({ type: "turn_end", message, toolResults: [] });
198					await emit({ type: "agent_end", messages: newMessages });
199					return;
200				}
201	
202				// Check for tool calls
203				const toolCalls = message.content.filter((c) => c.type === "toolCall");
204	
205				const toolResults: ToolResultMessage[] = [];
206				hasMoreToolCalls = false;
207				if (toolCalls.length > 0) {
208					const executedToolBatch = await executeToolCalls(currentContext, message, config, signal, emit);
209					toolResults.push(...executedToolBatch.messages);
210					hasMoreToolCalls = !executedToolBatch.terminate;
211	
212					for (const result of toolResults) {
213						currentContext.messages.push(result);
214						newMessages.push(result);
215					}
216				}
217	
218				await emit({ type: "turn_end", message, toolResults });
219	
220				const nextTurnContext = {
221					message,
222					toolResults,
223					context: currentContext,
224					newMessages,
225				};
226				const nextTurnSnapshot = await config.prepareNextTurn?.(nextTurnContext);
227				if (nextTurnSnapshot) {
228					currentContext = nextTurnSnapshot.context ?? currentContext;
229					config = {
230						...config,
231						model: nextTurnSnapshot.model ?? config.model,
232						reasoning:
233							nextTurnSnapshot.thinkingLevel === undefined
234								? config.reasoning
235								: nextTurnSnapshot.thinkingLevel === "off"
236									? undefined
237									: nextTurnSnapshot.thinkingLevel,
238					};
239				}
240	
241				if (
242					await config.shouldStopAfterTurn?.({
243						message,
244						toolResults,
245						context: currentContext,
246						newMessages,
247					})
248				) {
249					await emit({ type: "agent_end", messages: newMessages });
250					return;
251				}
252	
253				pendingMessages = (await config.getSteeringMessages?.()) || [];
254			}
255	
256			// Agent would stop here. Check for follow-up messages.
257			const followUpMessages = (await config.getFollowUpMessages?.()) || [];
258			if (followUpMessages.length > 0) {
259				// Set as pending so inner loop processes them
260				pendingMessages = followUpMessages;
261				continue;
262			}
263	
264			// No more messages, exit
265			break;
266		}
267	
268		await emit({ type: "agent_end", messages: newMessages });
269	}
