271	/**
272	 * Stream an assistant response from the LLM.
273	 * This is where AgentMessage[] gets transformed to Message[] for the LLM.
274	 */
275	async function streamAssistantResponse(
276		context: AgentContext,
277		config: AgentLoopConfig,
278		signal: AbortSignal | undefined,
279		emit: AgentEventSink,
280		streamFn?: StreamFn,
281	): Promise<AssistantMessage> {
282		// Apply context transform if configured (AgentMessage[] → AgentMessage[])
283		let messages = context.messages;
284		if (config.transformContext) {
285			messages = await config.transformContext(messages, signal);
286		}
287	
288		// Convert to LLM-compatible messages (AgentMessage[] → Message[])
289		const llmMessages = await config.convertToLlm(messages);
290	
291		// Build LLM context
292		const llmContext: Context = {
293			systemPrompt: context.systemPrompt,
294			messages: llmMessages,
295			tools: context.tools,
296		};
297	
298		const streamFunction = streamFn || streamSimple;
299	
300		// Resolve API key (important for expiring tokens)
301		const resolvedApiKey =
302			(config.getApiKey ? await config.getApiKey(config.model.provider) : undefined) || config.apiKey;
303	
304		const response = await streamFunction(config.model, llmContext, {
305			...config,
306			apiKey: resolvedApiKey,
307			signal,
308		});
309	
310		let partialMessage: AssistantMessage | null = null;
311		let addedPartial = false;
312	
313		for await (const event of response) {
314			switch (event.type) {
315				case "start":
316					partialMessage = event.partial;
317					context.messages.push(partialMessage);
318					addedPartial = true;
319					await emit({ type: "message_start", message: { ...partialMessage } });
320					break;
321	
322				case "text_start":
323				case "text_delta":
324				case "text_end":
325				case "thinking_start":
326				case "thinking_delta":
327				case "thinking_end":
328				case "toolcall_start":
329				case "toolcall_delta":
330				case "toolcall_end":
331					if (partialMessage) {
332						partialMessage = event.partial;
333						context.messages[context.messages.length - 1] = partialMessage;
334						await emit({
335							type: "message_update",
336							assistantMessageEvent: event,
337							message: { ...partialMessage },
338						});
339					}
340					break;
341	
342				case "done":
343				case "error": {
344					const finalMessage = await response.result();
345					if (addedPartial) {
346						context.messages[context.messages.length - 1] = finalMessage;
347					} else {
348						context.messages.push(finalMessage);
349					}
350					if (!addedPartial) {
351						await emit({ type: "message_start", message: { ...finalMessage } });
352					}
353					await emit({ type: "message_end", message: finalMessage });
354					return finalMessage;
355				}
356			}
357		}
358	
359		const finalMessage = await response.result();
360		if (addedPartial) {
361			context.messages[context.messages.length - 1] = finalMessage;
362		} else {
363			context.messages.push(finalMessage);
364			await emit({ type: "message_start", message: { ...finalMessage } });
365		}
366		await emit({ type: "message_end", message: finalMessage });
367		return finalMessage;
368	}
