370	/**
371	 * Execute tool calls from an assistant message.
372	 */
373	async function executeToolCalls(
374		currentContext: AgentContext,
375		assistantMessage: AssistantMessage,
376		config: AgentLoopConfig,
377		signal: AbortSignal | undefined,
378		emit: AgentEventSink,
379	): Promise<ExecutedToolCallBatch> {
380		const toolCalls = assistantMessage.content.filter((c) => c.type === "toolCall");
381		const hasSequentialToolCall = toolCalls.some(
382			(tc) => currentContext.tools?.find((t) => t.name === tc.name)?.executionMode === "sequential",
383		);
384		if (config.toolExecution === "sequential" || hasSequentialToolCall) {
385			return executeToolCallsSequential(currentContext, assistantMessage, toolCalls, config, signal, emit);
386		}
387		return executeToolCallsParallel(currentContext, assistantMessage, toolCalls, config, signal, emit);
388	}
389	
390	type ExecutedToolCallBatch = {
391		messages: ToolResultMessage[];
392		terminate: boolean;
393	};
394	
395	async function executeToolCallsSequential(
396		currentContext: AgentContext,
397		assistantMessage: AssistantMessage,
398		toolCalls: AgentToolCall[],
399		config: AgentLoopConfig,
400		signal: AbortSignal | undefined,
401		emit: AgentEventSink,
402	): Promise<ExecutedToolCallBatch> {
403		const finalizedCalls: FinalizedToolCallOutcome[] = [];
404		const messages: ToolResultMessage[] = [];
405	
406		for (const toolCall of toolCalls) {
407			await emit({
408				type: "tool_execution_start",
409				toolCallId: toolCall.id,
410				toolName: toolCall.name,
411				args: toolCall.arguments,
412			});
413	
414			const preparation = await prepareToolCall(currentContext, assistantMessage, toolCall, config, signal);
415			let finalized: FinalizedToolCallOutcome;
416			if (preparation.kind === "immediate") {
417				finalized = {
418					toolCall,
419					result: preparation.result,
420					isError: preparation.isError,
421				};
422			} else {
423				const executed = await executePreparedToolCall(preparation, signal, emit);
424				finalized = await finalizeExecutedToolCall(
425					currentContext,
426					assistantMessage,
427					preparation,
428					executed,
429					config,
430					signal,
431				);
432			}
433	
434			await emitToolExecutionEnd(finalized, emit);
435			const toolResultMessage = createToolResultMessage(finalized);
436			await emitToolResultMessage(toolResultMessage, emit);
437			finalizedCalls.push(finalized);
438			messages.push(toolResultMessage);
439		}
440	
441		return {
442			messages,
443			terminate: shouldTerminateToolBatch(finalizedCalls),
444		};
445	}
446	
447	async function executeToolCallsParallel(
448		currentContext: AgentContext,
449		assistantMessage: AssistantMessage,
450		toolCalls: AgentToolCall[],
451		config: AgentLoopConfig,
452		signal: AbortSignal | undefined,
453		emit: AgentEventSink,
454	): Promise<ExecutedToolCallBatch> {
455		const finalizedCalls: FinalizedToolCallEntry[] = [];
456	
457		for (const toolCall of toolCalls) {
458			await emit({
459				type: "tool_execution_start",
460				toolCallId: toolCall.id,
461				toolName: toolCall.name,
462				args: toolCall.arguments,
463			});
464	
465			const preparation = await prepareToolCall(currentContext, assistantMessage, toolCall, config, signal);
466			if (preparation.kind === "immediate") {
467				const finalized = {
468					toolCall,
469					result: preparation.result,
470					isError: preparation.isError,
471				} satisfies FinalizedToolCallOutcome;
472				await emitToolExecutionEnd(finalized, emit);
473				finalizedCalls.push(finalized);
474				continue;
475			}
476	
477			finalizedCalls.push(async () => {
478				const executed = await executePreparedToolCall(preparation, signal, emit);
479				const finalized = await finalizeExecutedToolCall(
480					currentContext,
481					assistantMessage,
482					preparation,
483					executed,
484					config,
485					signal,
486				);
487				await emitToolExecutionEnd(finalized, emit);
488				return finalized;
489			});
490		}
491	
492		const orderedFinalizedCalls = await Promise.all(
493			finalizedCalls.map((entry) => (typeof entry === "function" ? entry() : Promise.resolve(entry))),
494		);
495		const messages: ToolResultMessage[] = [];
496		for (const finalized of orderedFinalizedCalls) {
497			const toolResultMessage = createToolResultMessage(finalized);
498			await emitToolResultMessage(toolResultMessage, emit);
499			messages.push(toolResultMessage);
500		}
501	
502		return {
503			messages,
504			terminate: shouldTerminateToolBatch(orderedFinalizedCalls),
505		};
506	}
507	
508	type PreparedToolCall = {
509		kind: "prepared";
510		toolCall: AgentToolCall;
511		tool: AgentTool<any>;
512		args: unknown;
513	};
514	
515	type ImmediateToolCallOutcome = {
516		kind: "immediate";
517		result: AgentToolResult<any>;
518		isError: boolean;
519	};
520	
521	type ExecutedToolCallOutcome = {
522		result: AgentToolResult<any>;
523		isError: boolean;
524	};
525	
526	type FinalizedToolCallOutcome = {
527		toolCall: AgentToolCall;
528		result: AgentToolResult<any>;
529		isError: boolean;
530	};
531	
532	type FinalizedToolCallEntry = FinalizedToolCallOutcome | (() => Promise<FinalizedToolCallOutcome>);
533	
534	function shouldTerminateToolBatch(finalizedCalls: FinalizedToolCallOutcome[]): boolean {
535		return finalizedCalls.length > 0 && finalizedCalls.every((finalized) => finalized.result.terminate === true);
536	}
537	
538	function prepareToolCallArguments(tool: AgentTool<any>, toolCall: AgentToolCall): AgentToolCall {
539		if (!tool.prepareArguments) {
540			return toolCall;
541		}
542		const preparedArguments = tool.prepareArguments(toolCall.arguments);
543		if (preparedArguments === toolCall.arguments) {
544			return toolCall;
545		}
546		return {
547			...toolCall,
548			arguments: preparedArguments as Record<string, any>,
549		};
550	}
551	
552	async function prepareToolCall(
553		currentContext: AgentContext,
554		assistantMessage: AssistantMessage,
555		toolCall: AgentToolCall,
556		config: AgentLoopConfig,
557		signal: AbortSignal | undefined,
558	): Promise<PreparedToolCall | ImmediateToolCallOutcome> {
559		const tool = currentContext.tools?.find((t) => t.name === toolCall.name);
560		if (!tool) {
561			return {
562				kind: "immediate",
563				result: createErrorToolResult(`Tool ${toolCall.name} not found`),
564				isError: true,
565			};
566		}
567	
568		try {
569			const preparedToolCall = prepareToolCallArguments(tool, toolCall);
570			const validatedArgs = validateToolArguments(tool, preparedToolCall);
571			if (config.beforeToolCall) {
572				const beforeResult = await config.beforeToolCall(
573					{
574						assistantMessage,
575						toolCall,
576						args: validatedArgs,
577						context: currentContext,
578					},
579					signal,
580				);
581				if (beforeResult?.block) {
582					return {
583						kind: "immediate",
584						result: createErrorToolResult(beforeResult.reason || "Tool execution was blocked"),
585						isError: true,
586					};
587				}
588			}
589			return {
590				kind: "prepared",
591				toolCall,
592				tool,
593				args: validatedArgs,
594			};
595		} catch (error) {
596			return {
597				kind: "immediate",
598				result: createErrorToolResult(error instanceof Error ? error.message : String(error)),
599				isError: true,
600			};
601		}
602	}
603	
604	async function executePreparedToolCall(
605		prepared: PreparedToolCall,
606		signal: AbortSignal | undefined,
607		emit: AgentEventSink,
608	): Promise<ExecutedToolCallOutcome> {
609		const updateEvents: Promise<void>[] = [];
610	
611		try {
612			const result = await prepared.tool.execute(
613				prepared.toolCall.id,
614				prepared.args as never,
615				signal,
616				(partialResult) => {
617					updateEvents.push(
618						Promise.resolve(
619							emit({
620								type: "tool_execution_update",
621								toolCallId: prepared.toolCall.id,
622								toolName: prepared.toolCall.name,
623								args: prepared.toolCall.arguments,
624								partialResult,
625							}),
626						),
627					);
628				},
629			);
630			await Promise.all(updateEvents);
631			return { result, isError: false };
632		} catch (error) {
633			await Promise.all(updateEvents);
634			return {
635				result: createErrorToolResult(error instanceof Error ? error.message : String(error)),
636				isError: true,
637			};
638		}
639	}
640	
641	async function finalizeExecutedToolCall(
642		currentContext: AgentContext,
643		assistantMessage: AssistantMessage,
644		prepared: PreparedToolCall,
645		executed: ExecutedToolCallOutcome,
646		config: AgentLoopConfig,
647		signal: AbortSignal | undefined,
648	): Promise<FinalizedToolCallOutcome> {
649		let result = executed.result;
650		let isError = executed.isError;
651	
652		if (config.afterToolCall) {
653			try {
654				const afterResult = await config.afterToolCall(
655					{
656						assistantMessage,
657						toolCall: prepared.toolCall,
658						args: prepared.args,
659						result,
660						isError,
661						context: currentContext,
662					},
663					signal,
664				);
665				if (afterResult) {
666					result = {
667						content: afterResult.content ?? result.content,
668						details: afterResult.details ?? result.details,
669						terminate: afterResult.terminate ?? result.terminate,
670					};
671					isError = afterResult.isError ?? isError;
672				}
673			} catch (error) {
674				result = createErrorToolResult(error instanceof Error ? error.message : String(error));
675				isError = true;
676			}
677		}
678	
679		return {
680			toolCall: prepared.toolCall,
681			result,
682			isError,
683		};
684	}
685	
686	function createErrorToolResult(message: string): AgentToolResult<any> {
687		return {
688			content: [{ type: "text", text: message }],
689			details: {},
690		};
691	}
692	
693	async function emitToolExecutionEnd(finalized: FinalizedToolCallOutcome, emit: AgentEventSink): Promise<void> {
694		await emit({
695			type: "tool_execution_end",
696			toolCallId: finalized.toolCall.id,
697			toolName: finalized.toolCall.name,
698			result: finalized.result,
699			isError: finalized.isError,
700		});
701	}
702	
703	function createToolResultMessage(finalized: FinalizedToolCallOutcome): ToolResultMessage {
704		return {
705			role: "toolResult",
706			toolCallId: finalized.toolCall.id,
707			toolName: finalized.toolCall.name,
708			content: finalized.result.content,
709			details: finalized.result.details,
710			isError: finalized.isError,
711			timestamp: Date.now(),
712		};
713	}
714	
715	async function emitToolResultMessage(toolResultMessage: ToolResultMessage, emit: AgentEventSink): Promise<void> {
716		await emit({ type: "message_start", message: toolResultMessage });
717		await emit({ type: "message_end", message: toolResultMessage });
718	}
