60	// Extension shortcuts compete with canonical keybinding ids from keybindings.json.
61	// Only editor-global shortcuts are reserved here. Picker-specific bindings are not.
62	const RESERVED_KEYBINDINGS_FOR_EXTENSION_CONFLICTS = [
63		"app.interrupt",
64		"app.clear",
65		"app.exit",
66		"app.suspend",
67		"app.thinking.cycle",
68		"app.model.cycleForward",
69		"app.model.cycleBackward",
70		"app.model.select",
71		"app.tools.expand",
72		"app.thinking.toggle",
73		"app.editor.external",
74		"app.message.followUp",
75		"tui.input.submit",
76		"tui.select.confirm",
77		"tui.select.cancel",
78		"tui.input.copy",
79		"tui.editor.deleteToLineEnd",
80	] as const;
81	
82	type BuiltInKeyBindings = Partial<Record<KeyId, { keybinding: string; restrictOverride: boolean }>>;
83	
84	const buildBuiltinKeybindings = (resolvedKeybindings: KeybindingsConfig): BuiltInKeyBindings => {
85		const builtinKeybindings = {} as BuiltInKeyBindings;
86		for (const [keybinding, keys] of Object.entries(resolvedKeybindings)) {
87			if (keys === undefined) continue;
88			const keyList = Array.isArray(keys) ? keys : [keys];
89			const restrictOverride = (RESERVED_KEYBINDINGS_FOR_EXTENSION_CONFLICTS as readonly string[]).includes(keybinding);
90			for (const key of keyList) {
91				const normalizedKey = key.toLowerCase() as KeyId;
92				// If multiple actions bind the same key, the reserved action wins so extensions
93				// remain blocked by reserved shortcuts regardless of iteration order.
94				const existing = builtinKeybindings[normalizedKey];
95				if (existing?.restrictOverride && !restrictOverride) continue;
96				builtinKeybindings[normalizedKey] = {
97					keybinding,
98					restrictOverride,
99				};
100			}
101		}
102		return builtinKeybindings;
103	};
