111	/**
112	 * Events handled by the generic emit() method.
113	 * Events with dedicated emitXxx() methods are excluded for stronger type safety.
114	 */
115	type RunnerEmitEvent = Exclude<
116		ExtensionEvent,
117		| ToolCallEvent
118		| ToolResultEvent
119		| UserBashEvent
120		| ContextEvent
121		| BeforeProviderRequestEvent
122		| BeforeAgentStartEvent
