140		? SessionBeforeSwitchResult | undefined
141		: TEvent extends { type: "session_before_fork" }
142			? SessionBeforeForkResult | undefined
143			: TEvent extends { type: "session_before_compact" }
144				? SessionBeforeCompactResult | undefined
145				: TEvent extends { type: "session_before_tree" }
146					? SessionBeforeTreeResult | undefined
147					: undefined;
