176	/**
177	 * Helper function to emit session_shutdown event to extensions.
178	 * Returns true if the event was emitted, false if there were no handlers.
179	 */
180	export async function emitSessionShutdownEvent(
181		extensionRunner: ExtensionRunner,
182		event: SessionShutdownEvent,
