224	export class ExtensionRunner {
225		private extensions: Extension[];
226		private runtime: ExtensionRuntime;
227		private uiContext: ExtensionUIContext;
228		private cwd: string;
229		private sessionManager: SessionManager;
230		private modelRegistry: ModelRegistry;
231		private errorListeners: Set<ExtensionErrorListener> = new Set();
232		private getModel: () => Model<any> | undefined = () => undefined;
233		private isIdleFn: () => boolean = () => true;
234		private getSignalFn: () => AbortSignal | undefined = () => undefined;
235		private waitForIdleFn: () => Promise<void> = async () => {};
236		private abortFn: () => void = () => {};
237		private hasPendingMessagesFn: () => boolean = () => false;
238		private getContextUsageFn: () => ContextUsage | undefined = () => undefined;
239		private compactFn: (options?: CompactOptions) => void = () => {};
240		private getSystemPromptFn: () => string = () => "";
241		private newSessionHandler: NewSessionHandler = async () => ({ cancelled: false });
242		private forkHandler: ForkHandler = async () => ({ cancelled: false });
243		private navigateTreeHandler: NavigateTreeHandler = async () => ({ cancelled: false });
244		private switchSessionHandler: SwitchSessionHandler = async () => ({ cancelled: false });
245		private reloadHandler: ReloadHandler = async () => {};
246		private shutdownHandler: ShutdownHandler = () => {};
247		private shortcutDiagnostics: ResourceDiagnostic[] = [];
248		private commandDiagnostics: ResourceDiagnostic[] = [];
249		private staleMessage: string | undefined;
250	
251		constructor(
252			extensions: Extension[],
253			runtime: ExtensionRuntime,
254			cwd: string,
255			sessionManager: SessionManager,
256			modelRegistry: ModelRegistry,
257		) {
258			this.extensions = extensions;
259			this.runtime = runtime;
260			this.uiContext = noOpUIContext;
261			this.cwd = cwd;
262			this.sessionManager = sessionManager;
263			this.modelRegistry = modelRegistry;
264		}
265	
266		bindCore(
267			actions: ExtensionActions,
268			contextActions: ExtensionContextActions,
269			providerActions?: {
270				registerProvider?: (name: string, config: ProviderConfig) => void;
271				unregisterProvider?: (name: string) => void;
272			},
273		): void {
274			// Copy actions into the shared runtime (all extension APIs reference this)
275			this.runtime.sendMessage = actions.sendMessage;
276			this.runtime.sendUserMessage = actions.sendUserMessage;
277			this.runtime.appendEntry = actions.appendEntry;
278			this.runtime.setSessionName = actions.setSessionName;
279			this.runtime.getSessionName = actions.getSessionName;
280			this.runtime.setLabel = actions.setLabel;
281			this.runtime.getActiveTools = actions.getActiveTools;
282			this.runtime.getAllTools = actions.getAllTools;
283			this.runtime.setActiveTools = actions.setActiveTools;
284			this.runtime.refreshTools = actions.refreshTools;
285			this.runtime.getCommands = actions.getCommands;
286			this.runtime.setModel = actions.setModel;
287			this.runtime.getThinkingLevel = actions.getThinkingLevel;
288			this.runtime.setThinkingLevel = actions.setThinkingLevel;
289	
290			// Context actions (required)
291			this.getModel = contextActions.getModel;
292			this.isIdleFn = contextActions.isIdle;
293			this.getSignalFn = contextActions.getSignal;
294			this.abortFn = contextActions.abort;
295			this.hasPendingMessagesFn = contextActions.hasPendingMessages;
296			this.shutdownHandler = contextActions.shutdown;
297			this.getContextUsageFn = contextActions.getContextUsage;
298			this.compactFn = contextActions.compact;
299			this.getSystemPromptFn = contextActions.getSystemPrompt;
300	
301			// Flush provider registrations queued during extension loading
302			for (const { name, config, extensionPath } of this.runtime.pendingProviderRegistrations) {
303				try {
304					if (providerActions?.registerProvider) {
305						providerActions.registerProvider(name, config);
306					} else {
307						this.modelRegistry.registerProvider(name, config);
308					}
309				} catch (err) {
310					this.emitError({
311						extensionPath,
312						event: "register_provider",
313						error: err instanceof Error ? err.message : String(err),
314						stack: err instanceof Error ? err.stack : undefined,
315					});
316				}
317			}
318			this.runtime.pendingProviderRegistrations = [];
319	
320			// From this point on, provider registration/unregistration takes effect immediately
321			// without requiring a /reload.
322			this.runtime.registerProvider = (name, config) => {
323				if (providerActions?.registerProvider) {
324					providerActions.registerProvider(name, config);
325					return;
326				}
327				this.modelRegistry.registerProvider(name, config);
328			};
329			this.runtime.unregisterProvider = (name) => {
330				if (providerActions?.unregisterProvider) {
331					providerActions.unregisterProvider(name);
332					return;
333				}
334				this.modelRegistry.unregisterProvider(name);
335			};
336		}
337	
338		bindCommandContext(actions?: ExtensionCommandContextActions): void {
339			if (actions) {
340				this.waitForIdleFn = actions.waitForIdle;
341				this.newSessionHandler = actions.newSession;
342				this.forkHandler = actions.fork;
343				this.navigateTreeHandler = actions.navigateTree;
344				this.switchSessionHandler = actions.switchSession;
345				this.reloadHandler = actions.reload;
346				return;
347			}
348	
349			this.waitForIdleFn = async () => {};
350			this.newSessionHandler = async () => ({ cancelled: false });
351			this.forkHandler = async () => ({ cancelled: false });
352			this.navigateTreeHandler = async () => ({ cancelled: false });
353			this.switchSessionHandler = async () => ({ cancelled: false });
354			this.reloadHandler = async () => {};
355		}
356	
357		setUIContext(uiContext?: ExtensionUIContext): void {
358			this.uiContext = uiContext ?? noOpUIContext;
359		}
360	
361		getUIContext(): ExtensionUIContext {
362			return this.uiContext;
363		}
364	
365		hasUI(): boolean {
366			return this.uiContext !== noOpUIContext;
367		}
368	
369		getExtensionPaths(): string[] {
370			return this.extensions.map((e) => e.path);
371		}
372	
373		/** Get all registered tools from all extensions (first registration per name wins). */
374		getAllRegisteredTools(): RegisteredTool[] {
375			const toolsByName = new Map<string, RegisteredTool>();
376			for (const ext of this.extensions) {
377				for (const tool of ext.tools.values()) {
378					if (!toolsByName.has(tool.definition.name)) {
379						toolsByName.set(tool.definition.name, tool);
380					}
381				}
382			}
383			return Array.from(toolsByName.values());
384		}
385	
386		/** Get a tool definition by name. Returns undefined if not found. */
387		getToolDefinition(toolName: string): RegisteredTool["definition"] | undefined {
388			for (const ext of this.extensions) {
389				const tool = ext.tools.get(toolName);
390				if (tool) {
391					return tool.definition;
392				}
393			}
394			return undefined;
395		}
396	
397		getFlags(): Map<string, ExtensionFlag> {
398			const allFlags = new Map<string, ExtensionFlag>();
399			for (const ext of this.extensions) {
400				for (const [name, flag] of ext.flags) {
401					if (!allFlags.has(name)) {
402						allFlags.set(name, flag);
403					}
404				}
405			}
406			return allFlags;
407		}
408	
409		setFlagValue(name: string, value: boolean | string): void {
410			this.runtime.flagValues.set(name, value);
411		}
412	
413		getFlagValues(): Map<string, boolean | string> {
414			return new Map(this.runtime.flagValues);
415		}
416	
417		getShortcuts(resolvedKeybindings: KeybindingsConfig): Map<KeyId, ExtensionShortcut> {
418			this.shortcutDiagnostics = [];
419			const builtinKeybindings = buildBuiltinKeybindings(resolvedKeybindings);
420			const extensionShortcuts = new Map<KeyId, ExtensionShortcut>();
421	
422			const addDiagnostic = (message: string, extensionPath: string) => {
423				this.shortcutDiagnostics.push({ type: "warning", message, path: extensionPath });
424				if (!this.hasUI()) {
425					console.warn(message);
426				}
427			};
428	
429			for (const ext of this.extensions) {
430				for (const [key, shortcut] of ext.shortcuts) {
431					const normalizedKey = key.toLowerCase() as KeyId;
432	
433					const builtInKeybinding = builtinKeybindings[normalizedKey];
434					if (builtInKeybinding?.restrictOverride === true) {
435						addDiagnostic(
436							`Extension shortcut '${key}' from ${shortcut.extensionPath} conflicts with built-in shortcut. Skipping.`,
437							shortcut.extensionPath,
438						);
439						continue;
440					}
441	
442					if (builtInKeybinding?.restrictOverride === false) {
443						addDiagnostic(
444							`Extension shortcut conflict: '${key}' is built-in shortcut for ${builtInKeybinding.keybinding} and ${shortcut.extensionPath}. Using ${shortcut.extensionPath}.`,
445							shortcut.extensionPath,
446						);
447					}
448	
449					const existingExtensionShortcut = extensionShortcuts.get(normalizedKey);
450					if (existingExtensionShortcut) {
451						addDiagnostic(
