512		private resolveRegisteredCommands(): ResolvedCommand[] {
513			const commands: RegisteredCommand[] = [];
514			const counts = new Map<string, number>();
515	
516			for (const ext of this.extensions) {
517				for (const command of ext.commands.values()) {
518					commands.push(command);
519					counts.set(command.name, (counts.get(command.name) ?? 0) + 1);
520				}
521			}
522	
523			const seen = new Map<string, number>();
524			const takenInvocationNames = new Set<string>();
525	
526			return commands.map((command) => {
527				const occurrence = (seen.get(command.name) ?? 0) + 1;
528				seen.set(command.name, occurrence);
529	
530				let invocationName = (counts.get(command.name) ?? 0) > 1 ? `${command.name}:${occurrence}` : command.name;
531	
532				if (takenInvocationNames.has(invocationName)) {
533					let suffix = occurrence;
534					do {
535						suffix++;
536						invocationName = `${command.name}:${suffix}`;
537					} while (takenInvocationNames.has(invocationName));
538				}
539	
540				takenInvocationNames.add(invocationName);
541				return {
542					...command,
543					invocationName,
544				};
545			});
546		}
