636		createCommandContext(): ExtensionCommandContext {
637			// Use property descriptors instead of object spread so the guarded getters from
638			// createContext() stay lazy. A spread would eagerly read them once and freeze the
639			// old values into the returned object, bypassing stale-instance checks.
640			const context = Object.defineProperties(
641				{},
