671		private isSessionBeforeEvent(event: RunnerEmitEvent): event is SessionBeforeEvent {
672			return (
673				event.type === "session_before_switch" ||
674				event.type === "session_before_fork" ||
675				event.type === "session_before_compact" ||
676				event.type === "session_before_tree"
