680		async emit<TEvent extends RunnerEmitEvent>(event: TEvent): Promise<RunnerEmitResult<TEvent>> {
681			const ctx = this.createContext();
682			let result: SessionBeforeEventResult | undefined;
683	
684			for (const ext of this.extensions) {
685				const handlers = ext.handlers.get(event.type);
686				if (!handlers || handlers.length === 0) continue;
687	
688				for (const handler of handlers) {
689					try {
690						const handlerResult = await handler(event, ctx);
691	
692						if (this.isSessionBeforeEvent(event) && handlerResult) {
693							result = handlerResult as SessionBeforeEventResult;
694							if (result.cancel) {
695								return result as RunnerEmitResult<TEvent>;
696							}
697						}
698					} catch (err) {
699						const message = err instanceof Error ? err.message : String(err);
700						const stack = err instanceof Error ? err.stack : undefined;
701						this.emitError({
702							extensionPath: ext.path,
703							event: event.type,
704							error: message,
705							stack,
706						});
707					}
708				}
709			}
710	
711			return result as RunnerEmitResult<TEvent>;
712		}
