714		async emitMessageEnd(event: MessageEndEvent): Promise<AgentMessage | undefined> {
715			const ctx = this.createContext();
716			let currentMessage = event.message;
717			let modified = false;
718	
719			for (const ext of this.extensions) {
720				const handlers = ext.handlers.get("message_end");
721				if (!handlers || handlers.length === 0) continue;
722	
723				for (const handler of handlers) {
724					try {
725						const currentEvent: MessageEndEvent = { ...event, message: currentMessage };
726						const handlerResult = (await handler(currentEvent, ctx)) as MessageEndEventResult | undefined;
727						if (!handlerResult?.message) continue;
728	
729						if (handlerResult.message.role !== currentMessage.role) {
730							this.emitError({
731								extensionPath: ext.path,
732								event: "message_end",
733								error: "message_end handlers must return a message with the same role",
734							});
735							continue;
736						}
737	
738						currentMessage = handlerResult.message;
739						modified = true;
740					} catch (err) {
741						const message = err instanceof Error ? err.message : String(err);
742						const stack = err instanceof Error ? err.stack : undefined;
743						this.emitError({
744							extensionPath: ext.path,
745							event: "message_end",
746							error: message,
747							stack,
748						});
749					}
750				}
751			}
752	
753			return modified ? currentMessage : undefined;
754		}
