756		async emitToolResult(event: ToolResultEvent): Promise<ToolResultEventResult | undefined> {
757			const ctx = this.createContext();
758			const currentEvent: ToolResultEvent = { ...event };
759			let modified = false;
760	
761			for (const ext of this.extensions) {
762				const handlers = ext.handlers.get("tool_result");
763				if (!handlers || handlers.length === 0) continue;
764	
765				for (const handler of handlers) {
766					try {
767						const handlerResult = (await handler(currentEvent, ctx)) as ToolResultEventResult | undefined;
768						if (!handlerResult) continue;
769	
770						if (handlerResult.content !== undefined) {
771							currentEvent.content = handlerResult.content;
772							modified = true;
773						}
774						if (handlerResult.details !== undefined) {
775							currentEvent.details = handlerResult.details;
776							modified = true;
777						}
778						if (handlerResult.isError !== undefined) {
779							currentEvent.isError = handlerResult.isError;
780							modified = true;
781						}
782					} catch (err) {
783						const message = err instanceof Error ? err.message : String(err);
784						const stack = err instanceof Error ? err.stack : undefined;
785						this.emitError({
786							extensionPath: ext.path,
787							event: "tool_result",
788							error: message,
789							stack,
790						});
791					}
792				}
793			}
794	
795			if (!modified) {
796				return undefined;
797			}
798	
799			return {
800				content: currentEvent.content,
801				details: currentEvent.details,
802				isError: currentEvent.isError,
803			};
804		}
