899					try {
900						const event: BeforeProviderRequestEvent = {
901							type: "before_provider_request",
902							payload: currentPayload,
903						};
904						const handlerResult = await handler(event, ctx);
905						if (handlerResult !== undefined) {
906							currentPayload = handlerResult;
907						}
908					} catch (err) {
909						const message = err instanceof Error ? err.message : String(err);
910						const stack = err instanceof Error ? err.stack : undefined;
911						this.emitError({
