923	
924		async emitBeforeAgentStart(
925			prompt: string,
926			images: ImageContent[] | undefined,
927			systemPrompt: string,
928			systemPromptOptions: BuildSystemPromptOptions,
929		): Promise<BeforeAgentStartCombinedResult | undefined> {
930			let currentSystemPrompt = systemPrompt;
931			const ctx = Object.defineProperties(
932				{},
933				Object.getOwnPropertyDescriptors(this.createContext()),
934			) as ExtensionContext;
935			ctx.getSystemPrompt = () => {
936				this.assertActive();
937				return currentSystemPrompt;
938			};
939			const messages: NonNullable<BeforeAgentStartEventResult["message"]>[] = [];
940			let systemPromptModified = false;
941	
942			for (const ext of this.extensions) {
943				const handlers = ext.handlers.get("before_agent_start");
944				if (!handlers || handlers.length === 0) continue;
945	
946				for (const handler of handlers) {
947					try {
948						const event: BeforeAgentStartEvent = {
949							type: "before_agent_start",
950							prompt,
951							images,
952							systemPrompt: currentSystemPrompt,
953							systemPromptOptions,
954						};
955						const handlerResult = await handler(event, ctx);
956	
957						if (handlerResult) {
958							const result = handlerResult as BeforeAgentStartEventResult;
959							if (result.message) {
960								messages.push(result.message);
961							}
962							if (result.systemPrompt !== undefined) {
963								currentSystemPrompt = result.systemPrompt;
964								systemPromptModified = true;
965							}
966						}
967					} catch (err) {
968						const message = err instanceof Error ? err.message : String(err);
969						const stack = err instanceof Error ? err.stack : undefined;
970						this.emitError({
971							extensionPath: ext.path,
972							event: "before_agent_start",
973							error: message,
974							stack,
975						});
976					}
977				}
978			}
979	
980			if (messages.length > 0 || systemPromptModified) {
981				return {
982					messages: messages.length > 0 ? messages : undefined,
983					systemPrompt: systemPromptModified ? currentSystemPrompt : undefined,
984				};
985			}
986	
987			return undefined;
988		}
989	
990		async emitResourcesDiscover(
991			cwd: string,
992			reason: ResourcesDiscoverEvent["reason"],
993		): Promise<{
994			skillPaths: Array<{ path: string; extensionPath: string }>;
995			promptPaths: Array<{ path: string; extensionPath: string }>;
996			themePaths: Array<{ path: string; extensionPath: string }>;
997		}> {
998			const ctx = this.createContext();
999			const skillPaths: Array<{ path: string; extensionPath: string }> = [];
1000			const promptPaths: Array<{ path: string; extensionPath: string }> = [];
1001			const themePaths: Array<{ path: string; extensionPath: string }> = [];
1002	
1003			for (const ext of this.extensions) {
1004				const handlers = ext.handlers.get("resources_discover");
1005				if (!handlers || handlers.length === 0) continue;
1006	
1007				for (const handler of handlers) {
1008					try {
1009						const event: ResourcesDiscoverEvent = { type: "resources_discover", cwd, reason };
1010						const handlerResult = await handler(event, ctx);
1011						const result = handlerResult as ResourcesDiscoverResult | undefined;
1012	
1013						if (result?.skillPaths?.length) {
1014							skillPaths.push(...result.skillPaths.map((path) => ({ path, extensionPath: ext.path })));
1015						}
1016						if (result?.promptPaths?.length) {
1017							promptPaths.push(...result.promptPaths.map((path) => ({ path, extensionPath: ext.path })));
1018						}
1019						if (result?.themePaths?.length) {
1020							themePaths.push(...result.themePaths.map((path) => ({ path, extensionPath: ext.path })));
1021						}
1022					} catch (err) {
1023						const message = err instanceof Error ? err.message : String(err);
1024						const stack = err instanceof Error ? err.stack : undefined;
1025						this.emitError({
1026							extensionPath: ext.path,
1027							event: "resources_discover",
1028							error: message,
1029							stack,
1030						});
1031					}
1032				}
1033			}
1034	
1035			return { skillPaths, promptPaths, themePaths };
1036		}
1037	
1038		/** Emit input event. Transforms chain, "handled" short-circuits. */
1039		async emitInput(text: string, images: ImageContent[] | undefined, source: InputSource): Promise<InputEventResult> {
1040			const ctx = this.createContext();
1041			let currentText = text;
1042			let currentImages = images;
1043	
1044			for (const ext of this.extensions) {
1045				for (const handler of ext.handlers.get("input") ?? []) {
1046					try {
1047						const event: InputEvent = { type: "input", text: currentText, images: currentImages, source };
1048						const result = (await handler(event, ctx)) as InputEventResult | undefined;
1049						if (result?.action === "handled") return result;
1050						if (result?.action === "transform") {
1051							currentText = result.text;
1052							currentImages = result.images ?? currentImages;
1053						}
1054					} catch (err) {
1055						this.emitError({
1056							extensionPath: ext.path,
1057							event: "input",
1058							error: err instanceof Error ? err.message : String(err),
1059							stack: err instanceof Error ? err.stack : undefined,
1060						});
1061					}
1062				}
1063			}
1064			return currentText !== text || currentImages !== images
1065				? { action: "transform", text: currentText, images: currentImages }
1066				: { action: "continue" };
1067		}
1068	}
